script.inlineScript:
import { writeFileSync } from 'fs';

const baseUrl = process.env.APP_BASE_URL;
const apiKey = process.env.PLATFORM_API_KEY;

if (!baseUrl || !apiKey) {
  writeFileSync('/output/result.json', JSON.stringify({ options: [], error: 'Missing APP_BASE_URL or PLATFORM_API_KEY' }));
  process.exit(1);
}

try {
  const response = await fetch(`${baseUrl}/api/workflow-definitions`, {
    headers: { 'X-Api-Key': apiKey }
  });
  const body = await response.json();

  if (!response.ok) {
    writeFileSync('/output/result.json', JSON.stringify({ options: [], error: body.error || 'Failed to fetch workflows' }));
    process.exit(1);
  }

  const options = (body.definitions || []).filter(d => d.definition).map(d => ({
    label: `${d.definition.title || d.name} (v${d.latestVersion})`,
    description: d.definition.description || d.name,
    value: d.definition
  }));

  writeFileSync('/output/result.json', JSON.stringify({ options, summary: `Found ${options.length} workflow(s) available for editing` }));
} catch (err) {
  writeFileSync('/output/result.json', JSON.stringify({ options: [], error: `API call failed: ${err.message}` }));
  process.exit(1);
}

import { readFileSync, writeFileSync } from 'fs';

const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
const parsed = input.steps?.['design'] || input;
const errors = [];

if (!parsed || typeof parsed !== 'object') {
  errors.push('No WorkflowDefinition found in design step output');
} else {
  if (!parsed.name || typeof parsed.name !== 'string') errors.push('Missing or invalid: name (string)');
  if (typeof parsed.version !== 'number') errors.push('Missing or invalid: version (must be integer)');
  if (!Array.isArray(parsed.triggers) || parsed.triggers.length === 0) errors.push('Missing or empty: triggers');
  if (!Array.isArray(parsed.steps) || parsed.steps.length === 0) errors.push('Missing or empty: steps');
  if (!Array.isArray(parsed.transitions)) errors.push('Missing: transitions');

  if (Array.isArray(parsed.steps)) {
    const stepIds = parsed.steps.map(s => s.id);
    const terminals = parsed.steps.filter(s => s.type === 'terminal');
    if (terminals.length === 0) errors.push('Must have at least one terminal step');
    parsed.steps.forEach((step, i) => {
      if (!step.id) errors.push(`steps[${i}]: missing id`);
      if (!step.name) errors.push(`steps[${i}]: missing name`);
      if (!step.executor) errors.push(`steps[${i}]: missing executor`);
      if (step.verdicts) {
        Object.entries(step.verdicts).forEach(([k, v]) => {
          if (v.target && !stepIds.includes(v.target)) errors.push(`steps[${i}].verdicts.${k}.target '${v.target}' unknown`);
        });
      }
    });
    if (Array.isArray(parsed.transitions)) {
      parsed.transitions.forEach((t, i) => {
        if (!stepIds.includes(t.from)) errors.push(`transitions[${i}].from '${t.from}' unknown`);
        if (!stepIds.includes(t.to)) errors.push(`transitions[${i}].to '${t.to}' unknown`);
      });
    }
  }
}

writeFileSync('/output/result.json', JSON.stringify({ valid: errors.length === 0, errors, workflowDefinition: errors.length === 0 ? parsed : null }));

import { readFileSync, writeFileSync } from 'fs';

const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
const workflowDefinition = input.steps?.['validate']?.workflowDefinition || input.workflowDefinition;

if (!workflowDefinition || !workflowDefinition.name) {
  writeFileSync('/output/result.json', JSON.stringify({ registered: false, error: 'No WorkflowDefinition found in input' }));
  process.exit(0);
}

const baseUrl = process.env.APP_BASE_URL;
const apiKey = process.env.PLATFORM_API_KEY;

if (!baseUrl || !apiKey) {
  writeFileSync('/output/result.json', JSON.stringify({ registered: false, error: 'Missing APP_BASE_URL or PLATFORM_API_KEY' }));
  process.exit(0);
}

const ns = process.env.MEDIFORCE_RUN_NAMESPACE;
if (!ns) {
  writeFileSync('/output/result.json', JSON.stringify({ registered: false, error: 'Missing MEDIFORCE_RUN_NAMESPACE env var; cannot determine target namespace' }));
  process.exit(1);
}

const runId = process.env.RUN_ID;
const designerRunUrl = runId ? `${baseUrl}/${encodeURIComponent(ns)}/workflows/workflow-designer/runs/${encodeURIComponent(runId)}` : null;
const provenanceNote = designerRunUrl ? `\n\nBuilt with workflow designer (@${ns}) in run: ${designerRunUrl}` : `\n\nBuilt with workflow designer (@${ns})`;
workflowDefinition.description = (workflowDefinition.description || '') + provenanceNote;

try {
  const response = await fetch(`${baseUrl}/api/workflow-definitions?namespace=${encodeURIComponent(ns)}`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'X-Api-Key': apiKey },
    body: JSON.stringify(workflowDefinition),
  });
  const body = await response.json();
  if (response.ok) {
    const baseUrl = process.env.APP_BASE_URL || 'http://localhost:9003';
    writeFileSync('/output/result.json', JSON.stringify({ registered: true, name: body.name, version: body.version, namespace: ns, url: `${baseUrl}/${encodeURIComponent(ns)}/workflows/${encodeURIComponent(body.name)}`, summary: `Workflow '${body.name}' v${body.version} registered in @${ns}` }));
  } else {
    writeFileSync('/output/result.json', JSON.stringify({ registered: false, status: response.status, error: body.error || 'Registration failed' }));
  }
} catch (err) {
  writeFileSync('/output/result.json', JSON.stringify({ registered: false, error: `API call failed: ${err.message}` }));
}
